mapper.insert:
		/*
             SQL ID : LessonPageDAO.insert
             설  명 : 학습페이지 등록
         */

            SELECT IFNULL(MAX(PAGE_SEQNO), 0) + 1 FROM SBJCT_LCTR_CONTS_PAGE WHERE SBJCT_LCTR_CONTS_ID = #{lessonCntsId}

		INSERT INTO SBJCT_LCTR_CONTS_PAGE (
			  SBJCT_LCTR_CONTS_ID
			, PAGE_SEQNO
			, ULD_GBNCD
			, PAGENM
			, URL
			, VDO_MNTS
			, ATNDC_RFLTYN
			, OYN
			, RGTR_ID
			, FRST_INQ_DTTM
			, MDFR_ID
			, MOD_DTTM
		) VALUES (
			  #{lessonCntsId}
			, REPLACE(#{pageCnt}, '.0', '')
			, #{uploadGbn}
			, #{pageNm}
			, #{url}
			, #{videoTm}
			, #{atndYn}
			, #{openYn}
			, #{rgtrId}
			, FN_DTTM()
			, #{mdfrId}
			, FN_DTTM()
		)

mapper.update:
		/*
             SQL ID : LessonPageDAO.update
             설  명 : 학습페이지 수정
         */
		UPDATE SBJCT_LCTR_CONTS_PAGE
		SET 
			  MDFR_ID	= #{mdfrId}
			, MOD_DTTM	= FN_DTTM()

			, ULD_GBNCD = #{uploadGbn}


			, PAGENM = #{pageNm}


			, URL = #{url}


			, VDO_MNTS = #{videoTm}


			, ATNDC_RFLTYN = #{atndYn}


			, OYN = #{openYn}

		WHERE SBJCT_LCTR_CONTS_ID = #{lessonCntsId}
		AND PAGE_SEQNO = #{pageCnt}

mapper.delete:
		/*
             SQL ID : LessonPageDAO.delete
             설  명 : 학습페이지 삭제
         */
		DELETE FROM SBJCT_LCTR_CONTS_PAGE
		WHERE SBJCT_LCTR_CONTS_ID = #{lessonCntsId}

			AND PAGE_SEQNO = #{pageCnt}

		/*
             SQL ID : LessonPageDAO.deleteLessonStudyPage
             설  명 : 페이지 학습기록 삭제
         */
		DELETE FROM TB_LMS_LESSON_STUDY_PAGE
		WHERE SBJCT_LCTR_CONTS_ID = #{lessonCntsId}

			AND PAGE_SEQNO = #{pageCnt}

mapper.insert:
        /*
             SQL ID : insertLessonPageListForTrans
             설  명 : 페이지 목록 저장(선수강과목 이관용)
        */

        INSERT IGNORE INTO SBJCT_LCTR_CONTS_PAGE (
			  SBJCT_LCTR_CONTS_ID
			, PAGE_SEQNO
			, ULD_GBNCD
			, PAGENM
			, URL
			, VDO_MNTS
			, ATNDC_RFLTYN
			, OYN
			, RGTR_ID
			, FRST_INQ_DTTM
			, MDFR_ID
			, MOD_DTTM
		) VALUES

		( 
	          #{item.lessonCntsId}
	        , #{item.pageCnt}
	        , #{item.uploadGbn}
	        , #{item.pageNm}
	        , #{item.url}
	        , #{item.videoTm}
	        , #{item.atndYn}
        	, #{item.openYn}
			, #{item.rgtrId}
			, #{item.regDttm}
			, #{item.mdfrId}
			, #{item.modDttm}
		)

        /*
             SQL ID : insertLessonPageList
             설  명 : 콘텐츠페이지정보 목록 저장
        */

	        INSERT IGNORE INTO SBJCT_LCTR_CONTS_PAGE (
				  SBJCT_LCTR_CONTS_ID
				, PAGE_SEQNO
				, ULD_GBNCD
				, PAGENM
				, URL
				, VDO_MNTS
				, ATNDC_RFLTYN
				, OYN
				, RGTR_ID
				, FRST_INQ_DTTM
				, MDFR_ID
				, MOD_DTTM
	        ) 
	        SELECT
			          #{item.lessonCntsId}
			        , #{item.pageCnt}
			        , #{item.uploadGbn}
			        , #{item.pageNm}
			        , #{item.url}
			        , #{item.videoTm}
			        , #{item.atndYn}
		        	, #{item.openYn}
			        , #{item.rgtrId}
			        , FN_DTTM()
			        , #{item.rgtrId}
			        , FN_DTTM()
		    FROM DUAL
		    WHERE EXISTS (SELECT SBJCT_LCTR_CONTS_ID FROM TB_LMS_SBJCT_LCTR_CONTS WHERE SBJCT_LCTR_CONTS_ID = #{item.lessonCntsId})
	    	ON DUPLICATE KEY UPDATE
			      ULD_GBNCD = VALUES(ULD_GBNCD)
			    , PAGENM = VALUES(PAGENM)
			    , URL = VALUES(URL)
			    , VDO_MNTS = VALUES(VDO_MNTS)
			    , ATNDC_RFLTYN = VALUES(ATNDC_RFLTYN)
		    	, OYN = VALUES(OYN)
	    		, MDFR_ID = #{item.rgtrId}
	    		, MOD_DTTM = FN_DTTM()
